const raw = $json.output?.[0]?.content?.[0]?.text || $json.choices?.[0]?.message?.content;
if (!raw) throw new Error('No HOA email text found');
const input = $('Sample Property Input').first().json;

const escapedText = raw.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const htmlBody = '<html><body><div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;max-width:700px;padding:20px;">\n' +
  '<pre style="font-family:inherit;white-space:pre-wrap;margin:0;">' + escapedText + '</pre>\n' +
  '</div></body></html>';

const result = {
  json: {
    email_body: htmlBody,
    email_subject: 'NOTICE OF HOA VIOLATION \u2014 ' + input.street + ', ' + input.city,
    email_to: input.recipient_email,
    email_from: 'board@benttreeloophoa.org'
  }
};

if (input.demo_mode) {
  try {
    const imageBinary = $('Generate an image').first().binary;
    const binaryKeys = imageBinary ? Object.keys(imageBinary) : [];

    if (binaryKeys.length > 0) {
      const firstBinary = imageBinary[binaryKeys[0]];
      result.binary = {
        data: {
          ...firstBinary,
          fileName: firstBinary.fileName || 'hoa-violation-image.png'
        }
      };
    }
  } catch (e) {
    /* image binary not available */
  }
}

return [result];

