      "possible_encroachment": true,
      "notes": ["string"]
    },
    "occupancy_use": {
      "apparent_use": "single_family | multi_family | commercial | mixed | unknown | null",
      "over_occupancy_signs": true,
      "non_residential_activity": true,
      "notes": ["string"]
    }
  }
}

Rules:
- Always include all sections and fields.
- Use null when a value cannot be determined.
- Boolean fields: true only when clear evidence exists, false only when clearly absent, otherwise null.
- Do not infer violations here — this step is purely descriptive.

